const toolMeta = toolRegistry.get('my-tool');
if (toolMeta) {
  const route = {
    path: toolMeta.baseRoute.replace(/^\//, ''),
    loadChildren: toolMeta.loadChildren
  };
  router.resetConfig([ ...router.config, route ]);
  navigationService.rebuild(); // recomputa menu/breadcrumbs
}

const url = '/tools/my-tool/items/42';
const { item, breadcrumbs } = navigationService.resolveNavForUrl(url);
if (item) {
  router.navigateByUrl(item.url || url);
}
console.log('Breadcrumbs:', breadcrumbs.map(b => b.label).join(' > '));
